<template>

 <dv-border-box-11 :title="title" :titleWidth="titleWidth" :style="{'dv-border-box-11-title':{ fill:'#a4b1d1'},width:detail.style.position.w+'px',height: detail.style.position.h+'px'}">

 </dv-border-box-11>
</template>

<script>

import BaseView from '../View';
import ISMChildAutoMixin from '@/mixins/ISMChildAutoMixin'

export default {
  mixins: [ISMChildAutoMixin],
    name: 'dv-border-box11',
  inject: ['getNode'],
    props: {

    },
  created(){
    let _t = this
    this.GetNodeObj = this.getNode()
    this.GetNodeObj.on('change:data', ({ current }) => {
      if(current) {
        _t.detail = current.detail
      }
    })
    this.GetNodeObj.on('change:size', ({ current }) => {
      _t.detail.style.position.w = current.width
      _t.detail.style.position.h = current.height
    });
    this.detail = this.GetNodeObj.getData().detail
    this.editMode = this.GetNodeObj.getData().editMode
    this.showDeviceUuid = this.GetNodeObj.getData().showDeviceUuid
    this.IsToolBox = this.GetNodeObj.getData().IsToolBox
    _t.$EventBus.$on('cell-editMode', (data) => {
      _t.editMode = data.edit
      _t.IsToolBox = data.toolbox
    })
  },
    watch: {
      detail: {
        handler(newVal, oldVal) {
          this.setOption(newVal);
        },
        deep: true
      }
    },
    data() {
        return {
          detail:null,
          IsToolBox:false,
          editMode:true,
          base:{
            text: "configComponent.bigScreen.border.border11.title",
            icon: "data:image/png;base64,",
            isFontIcon: true,
            info: {
              type: "text",
              action: [],
              dataBind:
                [
                ],
              style: {
                position: {
                  x: 0,
                  y: 0,
                  w: 300,
                  h: 300
                },
                backColor: "transparent",
                zIndex: -1,
                transform: 0,
                diy:[
                  {
                    name:"configComponent.bigScreen.border.border11.titleValue",
                    type:4,
                    value:"标题",
                    key:"title",
                  },
                  {
                    name:"configComponent.bigScreen.border.border11.titleWidth",
                    type:1,
                    value:200,
                    min:100,
                    max:250,
                    key:"titleWidth",
                  }
                ]
              }
            }
          },
          title:"title",
          titleWidth:30
        }
    },
    methods: {
      setOption(option){
        for(let i=0;i<option.style.diy.length;i++)
        {
          if(option.style.diy[i].key=="title")
          {
            this.title=option.style.diy[i].value
          }
          if(option.style.diy[i].key=="titleWidth")
          {
            this.titleWidth=parseInt(option.style.diy[i].value)
          }
        }
      }
    },
    mounted() {
    this.$nextTick(function(){
      this.setOption(this.detail);
    });
  }
}
</script>

<style lang="less">
.view-text {
    height: 100%;
    width: 100%;
}
</style>
